// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below

// STRY0081883
var Utils = new TaskerUtils();

try{
	//RJ TEMPLATE PERMISSIONS UPDATE
	var allow = false;
	// STRY0081883 - deleting schedules is controlled by the users who can run them, not the users who can edit the templates
	var oUiConditionCheck =  new uiConditionCheck();
	var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
	if(grTemp.get(current.getValue('tasker_process')))
		allow = oUiConditionCheck.runTemplateUIAction(grTemp);
	answer = allow;
}catch(e) {

		var context = "Tasker | x_153465_discovert_tasker_schedule.delete";
		Utils.Catch(context, e);
		answer = false;
	}
